from fastapi import FastAPI
from pydantic import BaseModel
class DataInput(BaseModel):
description: str
data: bytes
model_config = {"val_json_bytes": "base64"}
class DataOutput(BaseModel):
description: str
data: bytes
model_config = {"ser_json_bytes": "base64"}
class DataInputOutput(BaseModel):
description: str
data: bytes
model_config = {
"val_json_bytes": "base64",
"ser_json_bytes": "base64",
}
app = FastAPI()
@app.post("/data")
def post_data(body: DataInput):
content = body.data.decode("utf-8")
return {"description": body.description, "content": content}
@app.get("/data")
def get_data() -> DataOutput:
data = "hello".encode("utf-8")
return DataOutput(description="A plumbus", data=data)
@app.post("/data-in-out")
def post_data_in_out(body: DataInputOutput) -> DataInputOutput:
return body
If you check the /docs
, they will show that the field data
expects base64 encoded bytes:
You could send a request like:
{
"description": "Some data",
"data": "aGVsbG8="
}
Tip
aGVsbG8=
is the base64 encoding of hello
.
And then Pydantic will decode the base64 string and give you the original bytes in the data
field of the model.
You will receive a response like:
{
"description": "Some data",
"content": "hello"
}
Pydantic bytes
for Output Data¶
You can also use bytes
fields with ser_json_bytes
in the model config for output data, and Pydantic will serialize the bytes as base64 when generating the JSON response.
from fastapi import FastAPI
from pydantic import BaseModel
# Code here omitted 👈
class DataOutput(BaseModel):
description: str
data: bytes
model_config = {"ser_json_bytes": "base64"}
# Code here omitted 👈
app = FastAPI()
# Code here omitted 👈
@app.get("/data")
def get_data() -> DataOutput:
data = "hello".encode("utf-8")
return DataOutput(description="A plumbus", data=data)
