Pydantic bytes
for Input and Output Data¶
And of course, you can use the same model configured to use base64 to handle both input (validate) with val_json_bytes
and output (serialize) with ser_json_bytes
when receiving and sending JSON data.
from fastapi import FastAPI
from pydantic import BaseModel
# Code here omitted 👈
class DataInputOutput(BaseModel):
description: str
data: bytes
model_config = {
"val_json_bytes": "base64",
"ser_json_bytes": "base64",
}
# Code here omitted 👈
app = FastAPI()
# Code here omitted 👈
@app.post("/data-in-out")
def post_data_in_out(body: DataInputOutput) -> DataInputOutput:
return body
